actionConfiguration.body:
select *
from public.update_quote_header(
	{{ Number(appsmith.store.selectedQuoteEventId || 0) }}::bigint,

	nullif(
		{{ (inpQuoteReference.text || "").trim() }},
		''
	)::text,

	{{
	dateQuoteValidUntil.selectedDate
	? moment(dateQuoteValidUntil.selectedDate).format("YYYY-MM-DD")
	: null
	}}::date,

	{{ selPricingMode.selectedOptionValue || "per_menu" }}::text,

	{{
	inpEventPriceTotal.text !== "" &&
	inpEventPriceTotal.text !== null &&
	inpEventPriceTotal.text !== undefined
	? Number(inpEventPriceTotal.text)
	: null
	}}::numeric,

	{{
	inpServiceCharge.text !== "" &&
	inpServiceCharge.text !== null &&
	inpServiceCharge.text !== undefined
	? Number(inpServiceCharge.text)
	: null
	}}::numeric,

	{{
	dateFinalDueDate.selectedDate
	? moment(dateFinalDueDate.selectedDate).format("YYYY-MM-DD")
	: null
	}}::date,

	nullif(
		{{
		rteQuoteCustomerNotes.text ||
		rteQuoteCustomerNotes.value ||
		""
		}},
		''
	)::text,

	nullif(
		{{
		rteQuoteInternalNotes.text ||
		rteQuoteInternalNotes.value ||
		""
		}},
		''
	)::text,

	nullif(
		{{
		rteQuoteTerms.text ||
		rteQuoteTerms.value ||
		""
		}},
		''
	)::text,

	nullif(
		{{ inpQuoVnuInstructions.text || "" }},
		''
	)::text
);
